function createBorderLineSurvey() {
  // Create a new Google Form
  var form = FormApp.create('BorderLine Cross-Border Student Need Survey');

  form.setDescription('Hi there! We’re building BorderLine—a platform designed to help African students and entry-level tech creators bypass legacy resume requirements, showcase their real skills, and connect directly to regional and global opportunities. Your anonymous responses will directly shape how we build this trust layer. It takes less than 2 minutes!');

  // -------------------------------------------------------------
  // SECTION 1: Demographics & Context
  // -------------------------------------------------------------
  form.addSectionHeaderItem()
      .setTitle('Section 1: Demographics & Context');

  // Q1: Country selection
  var countryList = form.addMultipleChoiceItem();
  countryList.setTitle('1. Which country are you currently studying or freelancing in?')
             .setChoices([
               countryList.createChoice('🇬🇭 Ghana'),
               countryList.createChoice('🇸🇳 Senegal'),
               countryList.createChoice('🇨🇮 Ivory Coast'),
               countryList.createChoice('🇿🇲 Zambia'),
               countryList.createChoice('🇲🇿 Mozambique'),
               countryList.createChoice('🇪🇹 Ethiopia')
             ])
             .setRequired(true);

  // Q2: Primary Tech Focus
  var techFocus = form.addMultipleChoiceItem();
  techFocus.setTitle('2. What is your primary area of tech focus?')
           .setChoices([
             techFocus.createChoice('Software Engineering / Web Development'),
             techFocus.createChoice('UI/UX Design'),
             techFocus.createChoice('Data Science / AI / Analytics'),
             techFocus.createChoice('Digital Marketing & Content Creation'),
             techFocus.createChoice('Other')
           ])
           .setRequired(true);

  // Q3: Status
  var status = form.addMultipleChoiceItem();
  status.setTitle('3. What is your current academic/professional status?')
        .setChoices([
          status.createChoice('University Student (Undergraduate)'),
          status.createChoice('Technical Bootcamp / Self-Taught Learner'),
          status.createChoice('Recent Graduate (Within 1 year)'),
          status.createChoice('Junior Freelancer')
        ])
        .setRequired(true);

  // -------------------------------------------------------------
  // SECTION 2: Uncovering "The Resume Trap" & Friction Points
  // -------------------------------------------------------------
  form.addPageBreakItem()
      .setTitle('Section 2: Uncovering "The Resume Trap" & Friction Points');

  // Q4: Barriers
  var barriers = form.addCheckboxItem();
  barriers.setTitle('4. What is the biggest barrier you face when applying for remote or regional tech opportunities? (Select all that apply)')
          .setChoices([
            barriers.createChoice('Job descriptions require 3+ years of experience for "entry-level" roles.'),
            barriers.createChoice('Traditional resumes don\'t capture my practical coding/design skills.'),
            barriers.createChoice('International platforms (like Upwork or Fiverr) favor established profiles with massive histories.'),
            barriers.createChoice('Lack of a professional network or industry connections.'),
            barriers.createChoice('Language barriers when applying to global or cross-border roles.')
          ]);

  // Q5: Showcasing work
  var showcase = form.addMultipleChoiceItem();
  showcase.setTitle('5. How do you currently showcase your technical or creative projects to prospective clients/employers?')
          .setChoices([
            showcase.createChoice('I send a standard Word/PDF resume with text descriptions.'),
            showcase.createChoice('I share links to raw, unorganized repositories (GitHub, Figma, Behance).'),
            showcase.createChoice('I don\'t have a structured way to show my work yet.'),
            showcase.createChoice('I built my own personal portfolio website (managed via hosting/code).')
          ])
          .setRequired(true);

  // Q6: Scale of Confidence
  var confidenceScale = form.addScaleItem();
  confidenceScale.setTitle('6. On a scale of 1 to 5, how confident do you feel that your current resume accurately represents what you can actually build?')
                 .setBounds(1, 5)
                 .setLabels('Not confident at all', 'Extremely confident')
                 .setRequired(true);

  // -------------------------------------------------------------
  // SECTION 3: Feature Validation & Accessibility Limits
  // -------------------------------------------------------------
  form.addPageBreakItem()
      .setTitle('Section 3: Feature Validation & Accessibility Limits');

  // Q7: AI Value Scale
  var aiValue = form.addScaleItem();
  aiValue.setTitle('7. If an AI could scan your messy project notes, class assignments, or GitHub links and instantly structure them into a polished, executive-ready portfolio case study, how valuable would that be to you?')
         .setBounds(1, 5)
         .setLabels('No value', 'Game changer')
         .setRequired(true);

  // Q8: Data costs
  var dataInterruption = form.addMultipleChoiceItem();
  dataInterruption.setTitle('8. How often does the cost of mobile data or poor internet connectivity disrupt your ability to search for work or update your online profiles?')
                  .setChoices([
                    dataInterruption.createChoice('Constantly (Daily issue)'),
                    dataInterruption.createChoice('Frequently (A few times a week)'),
                    dataInterruption.createChoice('Occasionally'),
                    dataInterruption.createChoice('Rarely / I have stable, unlimited Wi-Fi')
                  ])
                  .setRequired(true);

  // Q9: WhatsApp Validation
  var whatsappValidation = form.addMultipleChoiceItem();
  whatsappValidation.setTitle('9. Would you use a lightweight WhatsApp assistant to update your portfolio status or receive direct job matches without loading a heavy website?')
                    .setChoices([
                      whatsappValidation.createChoice('Yes, this would save me massive data and time.'),
                      whatsappValidation.createChoice('Maybe, depending on how easy it is to use.'),
                      whatsappValidation.createChoice('No, I prefer using a standard web browser on a laptop.')
                    ])
                    .setRequired(true);

  // Log the URL so the user can grab it
  Logger.log('Published URL: ' + form.getPublishedUrl());
  Logger.log('Edit URL: ' + form.getEditUrl());
}
